// Generated by AI (UnitTest MCP)
import { describe, expect, it } from "vitest";

import {
  designBoardRows,
  DesignItem,
  DesignPromotion,
  formatDesignPromotion,
  parseAdrMetadata,
} from "./designBoard";

const item = (overrides: Partial<DesignItem> = {}): DesignItem => ({
  id: "design:0026-constitution",
  adr_path: "docs/adr/0026-constitution.md",
  title: "Constitution",
  summary: "review governance",
  status: "proposed",
  proposed_by: "planner",
  decided_by: null,
  reason: null,
  created_at: 10,
  updated_at: 10,
  promotion_status: "not_required",
  spawned_goal_id: null,
  ...overrides,
});

const promotion = (): DesignPromotion => ({
  item: item({ status: "accepted", promotion_status: "materialized" }),
  goal: { id: "goal:ship", title: "Ship", kind: "objective" },
  tasks: [{ id: "task:one", title: "Implement", status: "open" }],
  constraints: [{ id: "goal:rule", title: "No shortcuts", kind: "constraint" }],
});

describe("parseAdrMetadata", () => {
  it("parses plain and bold status metadata and normalizes paths", () => {
    expect(
      parseAdrMetadata(
        "docs\\adr\\0026-constitution.md",
        "# Constitution\n\n- **Status:** Proposed\n",
        "workspace-sensor"
      )
    ).toEqual({
      adr_path: "docs/adr/0026-constitution.md",
      title: "Constitution",
      summary: "",
      status: "proposed",
      proposed_by: "workspace-sensor",
    });
    expect(parseAdrMetadata("docs/adr/0001.md", "# First\n- Status: Accepted\n")?.status).toBe(
      "accepted"
    );
  });

  it("rejects files without a structured title and supported status", () => {
    expect(parseAdrMetadata("docs/adr/no-title.md", "- Status: Proposed")).toBeNull();
    expect(parseAdrMetadata("docs/adr/no-status.md", "# No status")).toBeNull();
    expect(parseAdrMetadata("docs/adr/draft.md", "# Draft\n- Status: Draft")).toBeNull();
  });
});

describe("designBoardRows", () => {
  it("orders actionable states before durable history", () => {
    const rows = designBoardRows([
      item({ id: "rejected", status: "rejected", created_at: 4 }),
      item({
        id: "materialized",
        status: "accepted",
        promotion_status: "materialized",
        created_at: 3,
      }),
      item({ id: "pending", status: "accepted", promotion_status: "pending", created_at: 2 }),
      item({ id: "proposed", created_at: 1 }),
      item({
        id: "historical",
        status: "accepted",
        promotion_status: "not_required",
        created_at: 5,
      }),
    ]);

    expect(rows.map((row) => row.contextValue)).toEqual([
      "proposed",
      "pending",
      "materialized",
      "historical",
      "rejected",
    ]);
  });

  it("shows materialized objective and task provenance", () => {
    const materialized = promotion();
    const rows = designBoardRows(
      [materialized.item],
      new Map([[materialized.item.id, materialized]])
    );

    expect(rows[0].description).toBe("materialized · 1 tasks");
    expect(rows[0].tooltip).toContain("objective: Ship (goal:ship)");
    expect(rows[0].tooltip).toContain("tasks: 1; constraints: 1");
  });

  it("keeps historical accepted designs read-only while pending designs are actionable", () => {
    const rows = designBoardRows([
      item({ id: "historical", status: "accepted", promotion_status: "not_required" }),
      item({ id: "pending", status: "accepted", promotion_status: "pending" }),
    ]);

    expect(rows.find((row) => row.id === "pending")?.contextValue).toBe("pending");
    expect(rows.find((row) => row.id === "historical")?.contextValue).toBe("historical");
  });
});

describe("formatDesignPromotion", () => {
  it("renders objective, tasks, and constraints", () => {
    const markdown = formatDesignPromotion(promotion());
    expect(markdown).toContain("# Design materialization: Constitution");
    expect(markdown).toContain("**Objective:** Ship (goal:ship)");
    expect(markdown).toContain("Implement — open (task:one)");
    expect(markdown).toContain("No shortcuts — constraint (goal:rule)");
  });
});
